async function loadTranslations(selected){msg(t('loadingTranslations'));translations=await channelFetch('translations','/bible/translations');setOptions(els.translation,translations,selected||(translations[0]&&translations[0].translationKey),x=>({value:x.translationKey,label:`${x.abbreviation} — ${x.name}`}));msg(translations.length?'':t('noneInstalled'));return translations;}async function loadBooks(selected){if(!els.translation.value)return[];const books=await channelFetch('books','/bible/books?'+qs({translation:els.translation.value}));setOptions(els.book,books,selected,x=>({value:x.bookKey,label:x.name}));return loadChapters();}async function loadChapters(selected){if(!els.book.value)return[];const ch=await channelFetch('chapters','/bible/chapters?'+qs({translation:els.translation.value,book:els.book.value}));setOptions(els.chapter,ch,selected);return loadVerses();}async function loadVerses(start,end){if(!els.chapter.value)return[];const vs=await channelFetch('verses','/bible/verses?'+qs({translation:els.translation.value,book:els.book.value,chapter:els.chapter.value}));setOptions(els.start,vs,start,x=>({value:x.verse,label:x.verse}));setOptions(els.end,vs,end||start,x=>({value:x.verse,label:x.verse}));return vs;}
