function onInput(e){if(e.target===els.reference){invalidateResolvedPassage(t('chooseVerse'));}}
function onChange(e){if(e.target===els.translation){invalidateResolvedPassage(t('chooseVerse'));loadBooks().catch(err=>msg(err.message));}if(e.target===els.book){invalidateResolvedPassage(t('chooseVerse'));loadChapters().catch(err=>msg(err.message));}if(e.target===els.chapter){invalidateResolvedPassage(t('chooseVerse'));loadVerses().catch(err=>msg(err.message));}if(e.target===els.start||e.target===els.end){invalidateResolvedPassage(t('chooseVerse'));}if(e.target===els.cue){if(!els.cue.value){currentId=0;updateButtons();return;}const p=presets.find(x=>String(x.id)===els.cue.value);if(p)loadCue(p);}if(e.target.matches('[data-bible-template],[data-bible-position],[data-bible-scale],[data-bible-bg],[data-bible-bg-opacity],[data-bible-scripture-color],[data-bible-reference-color],[data-bible-align],[data-bible-show-verse-numbers],[data-bible-show-reference],[data-bible-show-translation],[data-bible-maximum-lines]')){const tr=resolved&&resolved.translation;if(tr&&tr.attributionRequired&&e.target.matches('[data-bible-show-reference],[data-bible-show-translation]'))e.target.checked=true;if(engine.getState().preview.bible)stage();}}
root.addEventListener('input',onInput);root.addEventListener('click',onClick);root.addEventListener('change',onChange);root.addEventListener('vh360:studio:program-source-change',updateButtons);root.addEventListener('vh360:studio:preview-source-change',updateButtons);unsubscribeEngine=engine.subscribe(updatePages);loadTranslations().then(()=>loadBooks()).catch(e=>{if(e.name!=='AbortError')msg(e.message);});loadCues().catch(()=>{});updateButtons();window.VH360StudioBible={destroy(){destroyed=true;Object.keys(controllers).forEach(k=>controllers[k].abort());if(unsubscribeEngine)unsubscribeEngine();root.removeEventListener('input',onInput);root.removeEventListener('click',onClick);root.removeEventListener('change',onChange);root.removeEventListener('vh360:studio:program-source-change',updateButtons);root.removeEventListener('vh360:studio:preview-source-change',updateButtons);}};
